init_eqs:
//Starting position
vx = rand(1);
vy = rand(1);

//Directions: -1 - inverse, 0 - forward
dirx = -1+int(rand(2));
diry = -1+int(rand(2));

speedoffset1 = .25 + rand(1)*.75;
speedoffset2 = .25 + rand(1)*.75;

dvd_r = .25+rand(1)*.75; dvd_g = .25+rand(1)*.75; dvd_b = .25+rand(1)*.75;

frame_eqs:
speed = (1/fps)*0.35;

//Check edge collisions, directions: -1 - inverse, 0 - forward
// --- RIGHT, TOP ---
dirx = if (vx >= 1, 0, dirx);
diry = if (vy >= 1, 0, diry);

// --- LEFT, BOTTOM ---
dirx = if (vx <= 0, -1, dirx);
diry = if (vy <= 0, -1, diry);

// Move it overtime
if (dirx, vx += speed*speedoffset1, vx -= speed*speedoffset1);
if (diry, vy += speed*speedoffset2, vy -= speed*speedoffset2);

q1 = vx;
q2 = vy;


//DVD Logo changes the color every edge bouncing
if (vx >= 1 || vy >=  1 || vx <= 0 || vy <= 0, dvd_r = .25+rand(1)*.75; dvd_g = .25+rand(1)*.75; dvd_b = .25+rand(1)*.75, 0);
q3 = dvd_r; q4 = dvd_g; q5 = dvd_b;
